sql:
SELECT status_description
FROM instrument_status
WHERE status = 'maintenance required';

SELECT COUNT(*) AS operational_instruments
FROM instrument_status
WHERE status = 'operational';

SELECT SUM(duration) AS total_usage_duration
FROM instrument_usage
WHERE instrument_id = 0;

SELECT calibration_date
FROM instrument_calibration_history
WHERE instrument_id = 0;

external_knowledge:
- 'on multiple missions' refers to instruments used in more than one project (project_count > 1);
- 'history of maintenance' refers to instruments with at least one maintenance record (maintenance_count > 0);
- 'fine-tuning' refers to instruments with at least one calibration history (calibration_count > 0);
- 'ready for action' refers to instruments with a status of 'operational'.

sql:
SELECT MAX(calibration_date) AS latest_calibration_date
FROM instrument_calibration_history
WHERE instrument_id = 1;

SELECT COUNT(*) AS calibration_count
FROM instrument_calibration_history
WHERE instrument_id = 1;
